import{Logger}from '../shared/logger.js';let progressBar=null;function createProgressBar(){if(progressBar)return;progressBar=document.createElement('div');progressBar.className='reading-progress-bar';progressBar.innerHTML='<div class="reading-progress-fill"></div>';const style=document.createElement('style');style.textContent=` .reading-progress-bar{position: fixed;top: 0;left: 0;width: 100%;height: 4px;background: rgba(0,0,0,0.1);z-index: 10001;}.reading-progress-fill{height: 100%;width: 0%;background: linear-gradient(90deg,#4caf50,#8bc34a);transition: width 0.1s ease;}@media(prefers-color-scheme: dark){.reading-progress-bar{background: rgba(255,255,255,0.1);}}`;document.head.appendChild(style);document.body.appendChild(progressBar);Logger.info('[ReadingProgress] Progress bar created');}function updateProgress(){if(!progressBar)return;const scrollTop=window.scrollY;const docHeight=document.documentElement.scrollHeight-window.innerHeight;const progress=docHeight>0 ?(scrollTop/docHeight)*100 : 0;const fill=progressBar.querySelector('.reading-progress-fill');if(fill){fill.style.width=`${Math.min(100,Math.max(0,progress))}%`;}}export function init(options={}){const{autoHide=true,color}=options;if(typeof window==='undefined')return;createProgressBar();if(color){const fill=progressBar.querySelector('.reading-progress-fill');if(fill){fill.style.background=color;}}let ticking=false;window.addEventListener('scroll',()=>{if(!ticking){window.requestAnimationFrame(()=>{updateProgress();if(autoHide){const scrollTop=window.scrollY;const docHeight=document.documentElement.scrollHeight-window.innerHeight;const atBottom=scrollTop>=docHeight-50;if(progressBar){progressBar.style.opacity=atBottom ? '0' : '1';}}ticking=false;});ticking=true;}},{passive: true});Logger.info('[ReadingProgress] Initialized');}export function destroy(){if(progressBar){progressBar.remove();progressBar=null;}Logger.info('[ReadingProgress] Destroyed');}export function getProgress(){const scrollTop=window.scrollY;const docHeight=document.documentElement.scrollHeight-window.innerHeight;return docHeight>0 ?(scrollTop/docHeight)*100 : 0;}if(typeof document!=='undefined'&&document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>init());}else{init();}